function solve(s) {
    const freq = {};
    for (const char of s) {
        freq[char] = (freq[char] || 0) + 1;
    }

    /**
     * Calculates the mirror character for a given character.
     * Assumes input char is a lowercase letter or a digit based on problem constraints.
     */
    const getMirrorChar = (c) => {
        const code = c.charCodeAt(0);

        // Letters (a-z)
        if (code >= 97 && code <= 122) { // 'a' to 'z'
            const aCode = 97;
            const i = code - aCode;
            const mirroredIndex = 25 - i;
            return String.fromCharCode(aCode + mirroredIndex);
        } 
        // Digits (0-9)
        else if (code >= 48 && code <= 57) { // '0' to '9'
            const zeroCode = 48;
            const j = code - zeroCode;
            const mirroredIndex = 9 - j;
            return String.fromCharCode(zeroCode + mirroredIndex);
        }
        return null; // Should not happen
    };

    let totalDifference = 0;

    // Use a Set to iterate over unique characters in string order for consistent processing, 
    // though iterating over Object.keys(freq) is sufficient if we enforce the c <= m rule.
    const uniqueChars = Object.keys(freq);

    for (const charC of uniqueChars) {
        const charM = getMirrorChar(charC);

        if (!charM) continue;

        // We only process the pair (C, M) if C is lexicographically less than or equal to M.
        // This ensures that each pair is counted exactly once.
        // If C == M (self-mirroring character, like 'm'/'n' if they were the same, or a digit like 4 mapping to 5 if 4=5 which is impossible), we process it.
        // For letters/digits, C == M only happens if C is the center point, which is impossible for 26 letters or 10 digits.
        if (charC > charM) {
            continue;
        }

        // Get frequencies. If the mirror character M is not in the string, its frequency is 0.
        const freqC = freq[charC];
        const freqM = freq[charM] || 0;

        // Calculate absolute difference
        const difference = Math.abs(freqC - freqM);

        totalDifference += difference;
    }

    return totalDifference;
}

