   */
  def getMirrorChar(c: Char): Char = {
    val code = c.toInt

    // Letters (a-z): ASCII 97 to 122
    if (code >= 97 && code <= 122) {
      // 'a' is index 0, 'z' is index 25.
      // Original index i = code - 97
      // Mirrored index = 25 - i
      val i = code - 97
      val mirroredIndex = 25 - i
